class Solution:
    def countPairs(self, coordinates: List[List[int]], k: int) -> int:
        freq = {}
        count = 0
        for x, y in coordinates:
            for prev_x, prev_y in freq:
                if (x ^ prev_x) + (y ^ prev_y) == k:
                    count += freq[(prev_x, prev_y)]
            freq[(x, y)] = freq.get((x, y), 0) + 1
        return count
